window.__QUIZ_DATA__=[{"id":"theory>Chemistry>2013>1>a>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"What is the common name given to the group VII elements?","images":[],"marking_scheme":"Group VII elements are generally known as 'halogen\".","marks":"3","difficulty":"1"},{"id":"theory>Chemistry>2013>1>a>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"Name the hydrides of the first two elements in group VII","images":[],"marking_scheme":"The first two elements of group VII are fluorine and chlorine. Their hydrides are given as,  Hydrogen Floride and Hydrogen Chloride.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>1>a>iii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"State three chemical properties of group VII elements","images":[],"marking_scheme":"- Halogen are very reactive elements and their reactivity decreases down the group   - They are all strong oxidizing agents   - Halogens are coloured and have odour   - Halogens combine with hydrogen to form gaseous covalent compounds","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>1>b","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"b","group":"","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"Copy and complete the following table   Particles Number of Neutrons Number of electrons Number of Protons Mass number W2+ 12  24X 2-   8 16 Y  13  27Z 12 11","images":[],"marking_scheme":"Particles Number of neutrons Number of electrons Number of protons Mass number W2+ 12 10 12 24X 2- 8 10 8 16Y 14 13 13 27Z 12 11 11 23  at W2+, number of protons = mass number - number of neutrons (24 - 12) = 12  Then, number of electrons would be 10 because two electrons have been lost.  at X2-, number of electrons would be 10 because two electrons is gained therefore proton would be 8 and neutron 8   at Y, number of protons would equal to number of electrons since it is a neutral atom while number of neutron would be (27-13)  = 14  at Z, number of protons would equal number of electrons since it is a neutral atom, and mass number would be sum of protons and neutrons i.e (11 + 12) = 23","marks":"5","difficulty":"3"},{"id":"theory>Chemistry>2013>1>c>i>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM","question":"Define this process:  Nuclear fission;","images":[],"marking_scheme":"Nuclear Fission is a process in which the nucleus of an atom is split, leading to the formation of atoms with nearly equal masses with a release of energy and radiations.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>1>c>i>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM","question":"Define this process: Nuclear fusion;","images":[],"marking_scheme":"Nuclear Fusion is a process in which two or more light nuclei combine to form a heavier nucleus with a release of energy and radiation.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2013>1>c>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM","question":"Give one use of each process in c(i).","images":[],"marking_scheme":"Nuclear fission is using in making bombs.  Nuclear fusion is used in generating electricity.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>1>d>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM","question":"List three types of radiation that are produced during radioactivity","images":[],"marking_scheme":"- Gamma radiation  - Beta radiation  - Alpha radiation","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2013>1>d>ii>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"","topic":"STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM","question":"Arrange the radiations listed in 1(d)(i) in order of increasing of penetrating power;","images":[],"marking_scheme":"In order of increasing increasing penetrating power, we have:  ALPHA  BETA  GAMMA","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2013>1>d>ii>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"","topic":"STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM","question":"Arrange the radiations listed in 1(d)(i) in order of increasing of Ionizing power","images":[],"marking_scheme":"In order of increasing ionizing power, we have:  GAMMA  BETA  ALPHA","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2013>2>a>i>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Define the term Normal salt;","images":[],"marking_scheme":"Normal salt is a salt formed when all the replaceable hydrogen ions in the acid have been completely replaced by a metallic ion or an ammonium ion.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>2>a>i>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Define the term Acid salt","images":[],"marking_scheme":"Acid salt is a salt formed when the replaceable hydrogen ions in acids are only partially replaced by a metallic or ammonium ion.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>2>a>ii>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"Tetraoxosulphate (VI) acid and sodium hydroxide react to produce salt and water.    Write a balance chemical equation for the formation of a normal salt","images":[],"marking_scheme":"H2SO 4(aq) + 2NaOH(aq)  \u21e2 Na2SO 4(aq)(normal salt) + 2H 2O (l)","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>2>a>ii>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"Tetraoxosulphate (VI) acid and sodium hydroxide react to produce salt and water.  Write a balance chemical equation for the formation of an acid salt","images":[],"marking_scheme":"H2SO4aq + NaOHaq \u21e2 NaHSO4(acid salt) + H2O(l)","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>2>b>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"ACIDS, BASES AND SALTS : ACID-BASE INDICATORS","question":"Explain briefly the term acid base indicator","images":[],"marking_scheme":"Acid base indicator: It is a dye which changes colour depending on the pH of the medium","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>2>b>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"","topic":"ACIDS, BASES AND SALTS : ACID-BASE INDICATORS","question":"Copy and complete the following table.   Indicator Colour in acidic medium Colour in basic medium Methyl orange  Phenolphthalein","images":[],"marking_scheme":"Indicator Colour in acidic medium Colour in basic mediumMethyl Orange Pink Yellow Phenolphthalein Colourless Pink","marks":"3","difficulty":"1"},{"id":"theory>Chemistry>2013>2>b>iii>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"For this titration, state the most suitable indicator for a strong acid against strong base","images":[],"marking_scheme":"Any indicator is suitable for this titration.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2013>2>b>iii>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"For this titration, state the most suitable indicator for a strong acid against weak base;","images":[],"marking_scheme":"Methyl orange is suitable for this titration.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>2>b>iii>III","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"For this  titrations, state the most suitable indicator:  Weak acid against strong base","images":[],"marking_scheme":"Phenolphthalein is a suitable indicator for this titration.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>2>c","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"c","group":"","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Baking soda and hydrochloric acid react according to the following equation:  NaNCO3(q)  + HCL(q) \u21e2 NaCl(q) + CO2(q) + H2Ol  Calculate the mass of baking soda that would produce 10g of carbon (IV) oxide.   [H = 1.00, C = 12.0, = 16.0, Na = 23.0]","images":[],"marking_scheme":"NaHCO3(aq) + HCl(aq) \u21e2 NaCl(aq) + CO2(g) + H2O(l)  molar mass of NaHCO3 (23+1+12+(3x16) = 84g)  molar mass of CO2 (12+(2x16)) = 12 + 32 = 44g  44g of CO2 required 84g NaHCO3   10g CO2 will require 84/44  x 10 = 19.1g CO2(g)","marks":"5","difficulty":"3"},{"id":"theory>Chemistry>2013>2>d","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : BASES","question":"Give a reason why a given mass of sodium hydroxide pellets cannot be used to prepare a standard solution","images":[],"marking_scheme":"It is hygroscopic in nature i.e it absorbs moisture from the atmosphere to become wet.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>3>a>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROCHEMICAL CELLS","question":"Define the term standard electrode potential","images":[],"marking_scheme":"Standard electrode potential of a metal ions system is the potential difference set up between the metal and a one molar solution of its ions at a temperature of 25oC","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>3>a>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"State three factors that affects the discharge of ions during electrolysis","images":[],"marking_scheme":"The factors include:  - The position of the ions in the electro-chemical series  - The concentration of the ions in the electrolyte   - The nature of the electrode","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2013>3>a>iii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROCHEMICAL CELLS","question":"State two functions of a salt bridge in an electrochemical cell.","images":[],"marking_scheme":"- It functions to complete the electric circuit   - It enables the movement of ions from one half-cell to the other","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>3>b","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"b","group":"","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Describe briefly what happens when a solution of copper (II) tetraoxosulphate (VI) is electrolysed using copper electrodes","images":["data:image/png;base64,"],"marking_scheme":"Electrolysis of copper II tetraoxosulphate VI using copper electrodes      At the anode (copper): Suppose a copper rod is used as the anode electrons can be supplied through the anode to the external circuit in three ways.   The SO24 \u21e2 SO4(g) + 2e-  the OH- ion in the solution could be discharged as gaseous oxygen and water   4OH-(aq) \u21e2 2H2O + O(2(g)) + 4e-  the metallic atoms on the anode surface might dissolve in the solution as ions, leaving their electrons behind.   Cus \u21e2 Cu2+aq + 2e-   The anode reduces in mass as the Cu atoms dissolve in the solution while the cathode increases in mass as Cu is deposited.","marks":"5","difficulty":"3"},{"id":"theory>Chemistry>2013>3>c","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"c","group":"FINAL","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Calculate the mass of copper deposited at the cathode when a current of 0.2 A is passed through a solution of copper (II) tetraoxosulphate (VI) for 35 minutes using copper electrodes.   [H = 1.00, O = 16.0, S = 32.0, Cu = 64.0, 1F = 96.500C]","images":[],"marking_scheme":"I = 0.2 A, t = 35 x 60 = 2100sec   Cu2+aq + 2e- \u21e2 Cu(s)  Q = It   = 0.2 x 2100   = 420C   From the ionic equation (2F = 64g Cu)  2 x 96500 C = 64   420C will give \u21e2 64 x 420C   2 x 96500 = 26880/2x96500   = 0.139  = 0.14g of Cu","marks":"4","difficulty":"3"},{"id":"theory>Chemistry>2013>3>d>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"State three characteristics of a catalyst.","images":[],"marking_scheme":"- It alters the rate of a reaction by creating alternative pathways   - It does not undergo any permanent change at the end of the reaction   - It lowers the energy barriers of a chemical reaction","marks":"3","difficulty":"1"},{"id":"theory>Chemistry>2013>3>d>ii>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Name one manufacturing process in which this metal is used as catalyst:    Iron","images":[],"marking_scheme":"Iron is used as a catalyst in the formation of ammonium gas.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>3>d>ii>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Name one manufacturing process in which this metal is used as catalyst:  Nickel","images":[],"marking_scheme":"Nickel is used as a catalyst in the formation of magarine from vegetable oil","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>3>d>ii>III","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Name one manufacturing process in which this metal is used as catalyst:  Platinum","images":[],"marking_scheme":"Plantinum is used as a catalyst in the formation of formal dehyde from methal alcohol vapours","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>4>a>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.","question":"Define the term hygroscopic","images":[],"marking_scheme":"Hygroscopy is the property of  a substance or compound which absorbs water when exposed to the atmosphere but will not form solution but becomes moist or wet.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>4>a>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.","question":"Give two differences between a physical change and a chemical change","images":[],"marking_scheme":"- Physical change is easily reversible while chemical change is not easily reversible.   - Physical change has no new substance produced while chemical change there is a new substance produced.   - Physical change: There is no change in mass of substance involved while in chemical change there is a change in mass of substance involved.","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2013>4>a>iii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"STATES OF MATTER : THE GAS LAWS","question":"Using the Kinetic theory of gases, explain briefly the charles' law","images":[],"marking_scheme":"Charles law states that the volume, V of fixed mass of gas varies directly with absolute temperature,T provided the pressure,P remains constant.   This means that molecule of a fixed mass of gas of known volume will increase as temperature increases.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>4>b>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS","question":"Arrange the following compounds in order of increasing boiling points:  CS2; CO2;NaH  Give reasons for your answer","images":[],"marking_scheme":"CO2 CS2, NaH   This is because, both CO2 and CS2 are covalent compounds. Their bond energies is lower compared to the electrovalent NaH. CSs is higher because oxygen is more reactive and less stable than sulphur.","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2013>4>b>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"","topic":"PERIODIC CHEMISTRY : REACTIONS BETWEEN ACIDS AND METALS, THEIR OXIDES AND TRIOXOCARBONATES (IV).","question":"Write a balance chemical equation to illustrate the reaction of chlorine gas with cold dilute sodium hydroxide","images":[],"marking_scheme":"Cl2(g) + 2NaOH(aq) \u21e2 NaClO(aq) + NaCl(aq) + H2O","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2013>4>c>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.","question":"In a certain reaction, 15.0g of impure magnesium sample reacted with excess hydrochloric acid liberating. 8.6dm3 of hydrogen gas at s.t.p.  Write a balance equation for the reaction","images":[],"marking_scheme":"Mg(s) + 2HCl(aq) \u21e2 MgCl2(aq) + H2(g)","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2013>4>c>ii>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"FINAL","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"In the reaction in c(i), 15.0g of impure magnesium sample reacted with excess hydrochloric acid liberating. 8.6dm3 of hydrogen gas at s.t.p.    Calculate the mass of pure magnesium in the sample;","images":[],"marking_scheme":"(I) From equation above   24g Mg liberated 22.4 dm3 H2  Xg Mg liberates 8.6 dm^3  X = 8.6 x 24/22.4 = 9.2g  The mass of pure magnesium in the sample is 9.2g","marks":"5","difficulty":"3"},{"id":"theory>Chemistry>2013>4>c>ii>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"FINAL","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"In the reaction in c(i), 15.0g of impure magnesium sample reacted with excess hydrochloric acid liberating. 8.6dm3 of hydrogen gas at s.t.p.  Calculate the percentage purity of the magnesium sample;  [Mg = 24; Volume at s.t.p 22.4 dm3, Avogadro's constant = 6.02 x 1023 mol-1]","images":[],"marking_scheme":"percentage purity   9.2/15.0 x 100   = 61.4%","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2013>4>c>ii>III","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"III","group":"","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"In the reaction in c(i), 15.0g of impure magnesium sample reacted with excess hydrochloric acid liberating. 8.6dm3 of hydrogen gas at s.t.p.  Number of Cl- ions produced in the reaction.","images":[],"marking_scheme":"MgCl2 \u21e2 Mg2+ + 2Cl-   1mol of Mg \u21e2 2moles of Cl  no of moles of Mg = mass/Molar mass  =9.2/24  =0.383 mol  No of moles of Cl- = 2 x no of moles of Mg  =2 x 0.383  =0.766moles  No of Cl- = 0.766 x 6.02 x 1023  =4.61 x 1023 ions","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2013>5>a>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Explain briefly the term chemical industry","images":[],"marking_scheme":"Chemical industry is the one that uses chemistry to make chemicals from other chemical substances. The chemical industry is founded on a wide variety of raw materials. The most important are coal, molasses, salt, mineral ores, water, air, and fats and oils of animals and plants origin.","marks":"4","difficulty":"1"},{"id":"theory>Chemistry>2013>5>a>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"State three factors that should be considered in siting a chemical industry","images":[],"marking_scheme":"- Raw materials  - Energy requirements  - Transport","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2013>5>b>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"Describe briefly how tin is extracted from its ore","images":[],"marking_scheme":"The tin ore Sno2 is crushed and washed with water. This process is described as the concentration of the ore. Then it is roasted in air to remove impurities like sulphur, arsenic and antimony as volatile oxides. The product is mixed with powered charcoal and heated to 1300oC to reduce the oxide.   SnO2(s) + 2Cs \u21e2 Snl + 2CO(2(g))","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2013>5>b>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"Give two uses of Tin","images":[],"marking_scheme":"- Tin is used in alloys together with lead, antimony and copper   - Tin is used in caning of food and drinks","marks":"3","difficulty":"1"},{"id":"theory>Chemistry>2013>5>c>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Name the constituents of cement","images":[],"marking_scheme":"The constituents that compose cement include calcium oxide and clay","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>5>c>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"How does mortar set?","images":[],"marking_scheme":"Mortar is a material used in masonry construction to fill the gaps between the bricks and blocks used in construction. Mortar is a mixture of sand, a binder such as cement or lime, and water and is applied as a paste which then sets hard.","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2013>5>d>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Explain briefly the term pollution","images":[],"marking_scheme":"Pollution is the release of harmful substances into the enviroment.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2013>5>d>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Give two examples of air pollution","images":[],"marking_scheme":"- Release of fumes from the exhaust of auto-mobiles.  - Irritable smell from animal dung","marks":"3","difficulty":"1"},{"id":"theory>Chemistry>2013>6>a>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION","question":"List two characteristics of a homologous series.","images":[],"marking_scheme":"- The members of a homologous series have a general molecular formula  - Successive homologous differ by -(CH) _2- groups","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2013>6>a>ii>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Consider the compound represented by the following formula: CH3(CH2)2CH3    Which homologous series does the compound belongs?","images":[],"marking_scheme":"The compound name is butane, it belongs to alkane homologous series.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2013>6>a>ii>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Consider the compound represented by the following formula: CH3(CH2)2CH3   Write the structures of three possible isomer of the compound","images":["data:image/png;base64,"],"marking_scheme":"Butane has only 2 possible isomers  -Butane  -Isobutane (2-methylpropane)","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2013>6>a>ii>III","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"III","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Consider the compound represented by the following formula: CH3(CH2)2CH3   Name the three possible isomer in 6(a)(ii)II.","images":[],"marking_scheme":"Only 2 possible isomers  n-butane  2 - methylpropane(isobutane)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2013>6>b>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"Write the structure of the major product formed in this reaction:    ethanol with excess acidified potassium tetraoxomaganate (VII)","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2013>6>b>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Write the structure of the major product formed in this reaction:  Excess ethane with chlorine in the presence of sunlight.","images":["data:image/jpeg;base64,"],"marking_scheme":"This reaction is called the substitution reaction. It occurs to produce Chloroethane","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2013>6>b>iii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"iii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS","question":"Write the structure of the major product formed in this reaction:  Ethanol with propanoic acid in the presence of few drops of concentrated tetraoxosulphate (VI) acid.","images":["data:image/png;base64,"],"marking_scheme":"This reaction is called esterification reaction.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2013>6>c","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS","question":"Name the major product in each reaction in 8(b)","images":[],"marking_scheme":"- Ethanoic acid   - Tetrachloroethane   - Ethyl propanoate","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2013>6>d>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP","question":"Consider the following organic compounds  X - (CH3)3COH;    Give the IUPAC name of each compound","images":["data:image/png;base64,"],"marking_scheme":"X is 2-methylpropan-2-ol  Y is Phenylmethanoic acid or benzoic acid","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2013>6>d>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP","question":"Consider the following organic compounds  X - (CH3)3COH;    State a chemical test for the functional group in each compound","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"Given: The Compound  X which is (CH3)3COH       - The functional group is - OH - since the compound is an alkanol.  - Alkanols can be tested for by reacting them in carboxylic acids, upon reacting, a compound with a fruity odour is formed (an alkanoate or an ester). This indicates the presence of -OH - functional group.  To sample X add some PCl5, steaming white fumes of HCl will be observed  To test for the functional group in Y(COOH):  Add (saturated solution) of NaHCO3/Na2CO3 to sample Y. Effervescence of colourless, odourless gas which turns lime water milky.  OR  To sample Y, add an alkanol in the presence of conc. H2SO4 or dry HCl. A pleasant fruity smell is produced, confirms -COOH in Y.","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>2013>6>e>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"An organic compound with relative molecular mass 136 contains 70.57% carbon, 5.90% hydrogen and 23.53% oxygen   Determine its empirical formula;  [H = 1.00, C = 12.0, O = 16.0]","images":["data:image/png;base64,"],"marking_scheme":"carbon C = 70.57%   hydrogen H = 5.90%   oxygen O = 23.53%           Calculate no of moles  C: 70.57/12=5.88  H: 5.90/1=5.90  O: 23.53/16=1.471  Divide by the smallest  C: 5.88/1.471=4  H: 5.90/1.471=4  O: 1.471/1.471=1  The empirical formula is  C4H4O","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2013>6>e>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"An organic compound with relative molecular mass 136 contains 70.57% carbon, 5.90% hydrogen and 23.53% oxygen   Determine its molecular formula;  [H = 1.00, C = 12.0, O = 16.0]","images":["data:image/png;base64,"],"marking_scheme":"carbon C = 70.57%   hydrogen H = 5.90%   oxygen O = 23.53%           (C4H4O)n=136  ((12*4) + 4 + 16)n=136  (48+4+16)n=136  68n=136  n=136/68  n=2  The molecular formula is C8H8O2","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2013>PAPER III>1>a>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"FINAL","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"[H = 1.00; O = 16.0; Na = 23.0; S = 32.0]  In a titration experiment 22.50cm3 of an acid solution A containing 10.6g of NaHSO4 per dm3 reacted with 25.0cm3 of solution B containing Xg of NaOH per dm3  The equation for the reaction is:   NaHSO4(aq) + NaOH(aq) \u2192 Na2SO4 + H2Ol   From the information given above, calculate the:     concentration of A in mol dm-3","images":[],"marking_scheme":"Molar Mass NaHSO4 = [23.0 + 1.00 + 32.0 + 64.0]   Conc. of A = 10.6120=0.0883moldm-3","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2013>PAPER III>1>a>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"FINAL","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"[H = 1.00; O = 16.0; Na = 23.0; S = 32.0]  In a titration experiment 22.50cm3 of an acid solution A containing 10.6g of NaHSO4 per dm3 reacted with 25.0cm3 of solution B containing Xg of NaOH per dm3  The equation for the reaction is:   NaHSO4(aq) + NaOH(aq) \u2192 Na2SO4 + H2Ol   From the information given above, calculate the:     concentration of B in mol dm-3","images":[],"marking_scheme":"Reaction: NaHSO4(aq) + NaOH(aq) \u2192 Na2SO(4aq) + H2Ol   From the reaction equation  CAVACBVB=11  CB=CAVAVB  CB=0.0883x22.525.0= 0.0795 mol/dm3","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2013>PAPER III>1>a>iii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"iii","group":"FINAL","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"[H = 1.00; O = 16.0; Na = 23.0; S = 32.0]  In a titration experiment 22.50cm3 of an acid solution A containing 10.6g of NaHSO4 per dm3 reacted with 25.0cm3 of solution B containing Xg of NaOH per dm3  The equation for the reaction is:   NaHSO4(aq) + NaOH(aq) \u2192 Na2SO4 + H2Ol   From the information given above, calculate the:     value of X","images":[],"marking_scheme":"Molar Mass of NaOH = (32.0 + 16.0 + 1.00) = 40gmol-1   Mass of NaOH gdm-3 = 40 x 0.0795= 3.18gdm-3   Value of X = 3.18","marks":"4","difficulty":"3"},{"id":"theory>Chemistry>2013>PAPER III>1>a>iv","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"iv","group":"FINAL","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"[H = 1.00; O = 16.0; Na = 23.0; S = 32.0]  In a titration experiment 22.50cm3 of an acid solution A containing 10.6g of NaHSO4 per dm3 reacted with 25.0cm3 of solution B containing Xg of NaOH per dm3  The equation for the reaction is:   NaHSO4(aq) + NaOH(aq) \u2192 Na2SO4 + H2Ol   From the information given above, calculate the:     mass of Na2SO4 formed during the reaction","images":[],"marking_scheme":"Amount of NaOH in 25.0cm3 of B = 25.0x0.07951000= 0.00199 mol  From the reaction equation   1 mol NaOH gives 1 mol. Na2SO4   \u2234 0.00199 mol NaOH = 0.00199 mol Na2SO4   Molar mass of Na2SO4 = (2 x 23.0) + 32.0 + (4 x 16.0)= 142gmol-1  Mass of Na2SO4 = 142 x 0.00199 = 0.283g      Alternative method 1   Amount of NaHSO4 in 22.50 cm3 of A   = 22.5x0.08831000 = 0.00199 mol   From the reaction equation:  1 mole of NaHSO4 gives 1 mol of Na2SO4   \u2234 0.00199 mol of NaHSO4 = 0.00199 mol of Na2SO4   Molar Mass of Na2SO4 = 142g mol-1   mass of Na2SO4 = 142 x 0.00199 = 0.283g      Alternative Method 2   Mass of NaOH in 25.0cm3 of 0.0795 moldm-3  m=MCV1000  = 40 x 0.0795 x 251000 = 0.0795g   Molar Mass of Na2SO4 = 142gmol-1   From the balance equation:   40g NaOH = 142g of Na2SO4   0.0795g NaOH = Xg Na2SO4   mass of Na2SO4 = 0.0795 x 142g40= 0.282g.","marks":"6","difficulty":"3"},{"id":"theory>Chemistry>2013>PAPER III>1>b>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACID-BASE INDICATORS","question":"Name a suitable indicator for the titration experiment.","images":[],"marking_scheme":"Phenolphtalein","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2013>PAPER III>1>b>ii>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"INTRODUCTION TO CHEMISTRY : MEASUREMENT OF PHYSICAL QUANTITIES.","question":"State the apparatus used to measure the volume of solution:   A","images":[],"marking_scheme":"Burette","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2013>PAPER III>1>b>ii>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"INTRODUCTION TO CHEMISTRY : MEASUREMENT OF PHYSICAL QUANTITIES.","question":"State the apparatus used to measure the volume of solution:   B","images":[],"marking_scheme":"Pipette","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2013>PAPER III>2","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"2","group":"","topic":"ACIDS, BASES AND SALTS : SALTS","question":"D is an inorganic salt   E is a solution of an inorganic salt. The tests recorded in the table below were performed on D and E.   Copy and complete the table.   Test Observation Inference(a) D + distilled water Did not dissolve ------- (b) D + dil. HCl + heat Dissolved to form blue or greenish-blue solution ------- (c) Solution of D + NaOH(aq) in drop then in excess Blue gelatinous precipitate ----- (d) Solution of D + NH3(aq) in drops then in excess ------- Cu2+ present Cu2+ confirmed(e) (i) Eaq + NaOHaq in drops and in excess No precipitate ------- (ii) Mixture in 2(2)(i) warmed ---------  NH3 gas evolved \u2234NH4+ present (f) Eaq + BaCl2(aq) + excess HCl White chalky precipitate No gas evolved; precipitate did not dissolve --------","images":[],"marking_scheme":"Test Observation Inference(a) D + distilled water Did not dissolve D is an insoluble salt (b) D + dil. HCl + heat Dissolved to form blue or green blue solution Cu2+ may be present (c) Solution of D + NaOH(aq) in drops then in excess Blue gelatinous precipitate Precipitate dissolves forming deep blue solution Cu2+ present (d) Solution of D + NH3(aq) in drops then in excess Blue gelatinous Precipitate Precipitate dissolves forming deep blue solution Cu2+ present Cu2+ present confirmed (e)(i) E(aq) + NaOH(aq) in drops and in excess No precipitate NH4+ may be present (ii) Mixture in 2(e)(i) warmed Colourless gas evolved Pungent/choking/irritating smell turns red litmus to blue/form dense white fume with conc. HCl NH3 gas evolved \u2234NH4+ present (f) E(aq) + BaCl2(aq) + excess HCl(aq) White chalky precipitate No gas evolved Precipitate did not dissolve CO32- SO42- SO42- Present","marks":"14","difficulty":"3"},{"id":"theory>Chemistry>2013>PAPER III>3>a>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Draw a labelled diagram of a simple set-up that can be used to distinguished between an electrolyte and a non-electrolyte","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2013>PAPER III>3>a>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"What is the name of the set-up drawn in 3(a)(i)?","images":[],"marking_scheme":"Electrolytic cell","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2013>PAPER III>3>a>iii>I","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Name one:  electrolyte;","images":[],"marking_scheme":"I - Tetraoxosulphate (VI) acid   - sodium chloride solution","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2013>PAPER III>3>a>iii>II","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"non-electrolyte","images":[],"marking_scheme":"- Glucose solution   - Sugar solution   - Petrol/Kerosene","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2013>PAPER III>3>b","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES","question":"Name one reagent that could be used to distinguish between the following ions in qualitative analysis:  Ca2+; Pb2+; Zn2+ and Al3+.","images":[],"marking_scheme":"The reagent that can be used is aqueous ammonia  -Ca2+ will have no reaction  -Pb2+ and Al3+ will form white precipitate insoluble in excess NH3(aq)  -Zn2+ will form white precipitate soluble in excess NH3(aq)","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2013>PAPER III>3>c>i","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES","question":"State the observation that could be used to distinguish between the following ions in qualitative analysis:   Ca2+; Pb2+; Zn2+ and Al3+","images":[],"marking_scheme":"-Ca2+ will have no visible reaction with NH3(aq)  -Pb2+ and Al3+ will form white precipitate insoluble in excess NH3(aq)  -Zn2+ will form white precipitate soluble in excess NH3(aq)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2013>PAPER III>3>c>ii","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"ii","group":"","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES","question":"State the observation that could be made in each case with the named reagent in 3(c)(i)","images":[],"marking_scheme":"Ca2+ - No precipitate with NH3(aq)   Pb2+ - White chalky precipitate insoluble in excess   Zn2+ - White gelatinous precipitate solution in excess   Al3+ - White gelatinous precipitate insoluble in excess","marks":"5","difficulty":"2"},{"id":"theory>Chemistry>2013>PAPER III>3>d","subject":"Chemistry","year":"2013","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACID-BASE TITRATION","question":"Explain briefly the term end-point.","images":[],"marking_scheme":"End point is a stage/point in a titration where a given amount of reagent in a solution (acid, oxidizing agent) completely react with another reagent (base, reading agent). It is usually indicated by colour change.","marks":"2","difficulty":"1"}];